import React from 'react';
import { ChevronLeft, ChevronRight } from 'lucide-react';

const images = [
  'https://picsum.photos/1920/800?random=1',
  'https://picsum.photos/1920/800?random=2',
  'https://picsum.photos/1920/800?random=3',
  'https://picsum.photos/1920/800?random=4',
];

const HeroSlider: React.FC = () => {
  const [current, setCurrent] = React.useState(0);

  React.useEffect(() => {
    const timer = setInterval(() => {
      setCurrent((prev) => (prev + 1) % images.length);
    }, 3000);
    return () => clearInterval(timer);
  }, []);

  const next = () => setCurrent((prev) => (prev + 1) % images.length);
  const prev = () => setCurrent((prev) => (prev - 1 + images.length) % images.length);

  return (
    <div className="relative w-full h-[400px] md:h-[600px] overflow-hidden bg-slate-900">
      {images.map((img, index) => (
        <div
          key={index}
          className={`absolute inset-0 transition-opacity duration-1000 ease-in-out ${
            index === current ? 'opacity-100' : 'opacity-0'
          }`}
        >
          <img
            src={img}
            alt={`Slide ${index + 1}`}
            className="w-full h-full object-cover"
          />
          <div className="absolute inset-0 bg-black/40 flex items-center justify-center">
            <div className="text-center text-white px-4">
              <h2 className="text-4xl md:text-6xl font-bold mb-4 animate-slideUp">
                {index === 0 && "Impulsione sua Carreira"}
                {index === 1 && "Conhecimento que Transforma"}
                {index === 2 && "Estratégias de Sucesso"}
                {index === 3 && "Consultoria Especializada"}
              </h2>
              <p className="text-lg md:text-xl font-light mb-8 max-w-2xl mx-auto">
                No Universo Cursos e Consultoria, nós conectamos você aos melhores especialistas do mercado.
              </p>
              <button className="bg-blue-600 hover:bg-blue-700 text-white px-8 py-3 rounded-md font-bold text-lg transition-colors shadow-lg">
                Saiba Mais
              </button>
            </div>
          </div>
        </div>
      ))}

      {/* Navigation arrows */}
      <button
        onClick={prev}
        className="absolute left-4 top-1/2 -translate-y-1/2 p-2 rounded-full bg-white/20 hover:bg-white/40 text-white transition-all"
      >
        <ChevronLeft size={32} />
      </button>
      <button
        onClick={next}
        className="absolute right-4 top-1/2 -translate-y-1/2 p-2 rounded-full bg-white/20 hover:bg-white/40 text-white transition-all"
      >
        <ChevronRight size={32} />
      </button>

      {/* Dots */}
      <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex space-x-2">
        {images.map((_, index) => (
          <button
            key={index}
            onClick={() => setCurrent(index)}
            className={`w-3 h-3 rounded-full transition-all ${
              index === current ? 'bg-blue-500 w-8' : 'bg-white/50'
            }`}
          />
        ))}
      </div>
    </div>
  );
};

export default HeroSlider;

import React from 'react';
import { Briefcase, Rocket, Users, BarChart } from 'lucide-react';

interface CourseCardProps {
  title: string;
  description: string;
  icon: string;
}

const CourseCard: React.FC<CourseCardProps> = ({ title, description, icon }) => {
  const renderIcon = () => {
    switch (icon) {
      case 'Briefcase': return <Briefcase size={32} />;
      case 'Rocket': return <Rocket size={32} />;
      case 'Users': return <Users size={32} />;
      case 'BarChart': return <BarChart size={32} />;
      default: return <Briefcase size={32} />;
    }
  };

  return (
    <div className="group p-8 bg-white border border-gray-100 rounded-2xl shadow-sm hover:shadow-xl transition-all duration-300 hover:-translate-y-2">
      <div className="w-16 h-16 bg-blue-50 text-blue-600 rounded-xl flex items-center justify-center mb-6 group-hover:bg-blue-600 group-hover:text-white transition-colors">
        {renderIcon()}
      </div>
      <h3 className="text-xl font-bold text-slate-900 mb-3">{title}</h3>
      <p className="text-slate-600 leading-relaxed">
        {description}
      </p>
      <button className="mt-6 text-blue-600 font-semibold flex items-center group-hover:underline">
        Saiba mais 
        <span className="ml-1">→</span>
      </button>
    </div>
  );
};

export default CourseCard;

